/**
 * 参考答案を id（essayProblems.id と同一）で取得する。
 * 未投入問は undefined → UI 側で「参考答案準備中」フォールバックを表示する。
 */
export function getEssaySampleAnswer(id: string): EssaySampleAnswer | undefined {
  return essaySampleAnswers[id]
}
